const payload = $json.body ?? $json;
const action = String(payload.action ?? '').trim().toLowerCase();
const timezone = 'America/Argentina/Buenos_Aires';

function nowDateInTZ(tz) {
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  return fmt.format(new Date()); // YYYY-MM-DD
}

return [
  {
    json: {
      ...payload,
      action,
      timezone,
      request_ts: new Date().toISOString(),
      today_tz: nowDateInTZ(timezone),
    },
  },
];

const input = $json;
const allowedActions = new Set(['alta','search', 'influencers_search', 'consulta', 'extension', 'baja_manual', 'listar_ads', 'run_now', 'history', 'pause_ad', 'pause_active']);

function isValidDateFormat(value) {
  if (typeof value !== 'string') return false;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(value)) return false;
  const [y, m, d] = value.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d));
  return dt.getUTCFullYear() === y && dt.getUTCMonth() === (m - 1) && dt.getUTCDate() === d;
}

function toBool(value, fallback = false) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const normalized = String(value).trim().toLowerCase();
  return ['1', 'true', 'si', 'yes', 'y'].includes(normalized);
}

function normalizeB64(value) {
  const raw = String(value || '').trim().replace(/-/g, '+').replace(/_/g, '/');
  const padding = raw.length % 4;
  return padding ? raw + '='.repeat(4 - padding) : raw;
}

function badRequest(message, details = {}) {
  const err = new Error(message);
  err.name = 'ValidationError';
  err.details = details;
  throw err;
}

if (!allowedActions.has(input.action)) {
  badRequest('`action` invalida. Usar: alta | search | consulta | extension | baja_manual | listar_ads | run_now | history | pause_ad | pause_active', { action: input.action });
}

input.actor = String(input.requested_by ?? input.actor ?? 'ops@adskiller').trim();
input.correlation_id = String(input.correlation_id ?? `ak-ui-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);

// ── Normalizar aliases de campo del frontend hacia nombres internos GS ──────────
// Frontend envía: influencer_name, end_date
// GS espera:      Cliente,          Fecha_Fin
if (input.influencer_name && !input.Cliente) input.Cliente = input.influencer_name;
if (input.end_date && !input.Fecha_Fin)      input.Fecha_Fin = input.end_date;
if (input.new_end_date && !input.Nueva_Fecha_Fin) input.Nueva_Fecha_Fin = input.new_end_date;
if (input.contract_id && !input.Contrato_ID) input.Contrato_ID = input.contract_id;
if (input.ad_id && !input.Ad_ID)             input.Ad_ID = input.ad_id;

if (input.action === 'alta') {
  // Solo requiere nombre del influencer y fecha fin.
  // Contrato_ID y Regex_Anuncio se auto-generan en Prepare Alta Row.
  if (!String(input.Cliente ?? '').trim()) {
    badRequest('influencer_name (o Cliente) es obligatorio para alta');
  }
  if (!String(input.Fecha_Fin ?? '').trim()) {
    badRequest('end_date (o Fecha_Fin) es obligatorio para alta');
  }
  if (!isValidDateFormat(input.Fecha_Fin)) {
    badRequest('end_date invalido. Formato requerido: YYYY-MM-DD');
  }
  const endDateObj = new Date(input.Fecha_Fin + 'T00:00:00Z');
  if (endDateObj <= new Date()) {
    badRequest('end_date debe ser una fecha futura');
  }
}

if (input.action === 'extension') {
  if (!String(input.Contrato_ID ?? '').trim()) badRequest('contract_id es obligatorio para extension');
  if (!String(input.Nueva_Fecha_Fin ?? '').trim()) badRequest('new_end_date es obligatorio para extension');
  if (!isValidDateFormat(input.Nueva_Fecha_Fin)) badRequest('new_end_date invalido. Formato requerido: YYYY-MM-DD');
}

if (input.action === 'search') {
  if (!String(input.q ?? '').trim()) badRequest('q es obligatorio para search');
  input.q = String(input.q).trim();
}

if (input.action === 'consulta') {
  // show_all=true devuelve todos los contratos sin filtrar por fecha ni status
  const showAll = input.show_all === true || String(input.show_all ?? '').toLowerCase() === 'true';
  input.show_all = showAll;
  if (!showAll) {
    const dias = Number(input.dias_proximos ?? 60);
    if (!Number.isInteger(dias) || dias < 1 || dias > 365) badRequest('dias_proximos invalido. Debe ser entero entre 1 y 365');
    input.dias_proximos = dias;
  }
}

if (input.action === 'baja_manual' || input.action === 'listar_ads' || input.action === 'pause_ad' || input.action === 'pause_active') {
  if (!String(input.Contrato_ID ?? '').trim()) badRequest('contract_id es obligatorio para esta accion');
}

if (input.action === 'pause_ad' && !String(input.Ad_ID ?? '').trim()) {
  badRequest('ad_id es obligatorio para pause_ad');
}

if (input.action === 'pause_active') {
  const dryRun = toBool(input.dry_run, true);
  const maxBatchSize = Number(input.max_batch_size ?? input.batch_limit ?? 20);
  if (!Number.isInteger(maxBatchSize) || maxBatchSize < 1 || maxBatchSize > 100) {
    badRequest('max_batch_size invalido. Debe ser entero entre 1 y 100');
  }
  input.dry_run = dryRun;
  input.max_batch_size = maxBatchSize;
  input.batch_limit = maxBatchSize;

  if (dryRun) {
    input.action = 'pause_active_preview';
  } else {
    const confirmToken = String(input.confirm_token ?? '').trim();
    if (!confirmToken) badRequest('confirm_token es obligatorio cuando dry_run=false');
    try {
      const decoded = JSON.parse(Buffer.from(normalizeB64(confirmToken), 'base64').toString('utf8'));
      const tokenContractId = String(decoded.contract_id ?? '').trim();
      const tokenBatchSize = Number(decoded.max_batch_size ?? 0);
      const expiresAt = Number(decoded.expires_at_epoch_ms ?? 0);
      if (!tokenContractId || tokenContractId !== String(input.Contrato_ID).trim()) badRequest('confirm_token no corresponde al contract_id enviado');
      if (!Number.isInteger(tokenBatchSize) || tokenBatchSize !== maxBatchSize) badRequest('confirm_token no corresponde al max_batch_size enviado');
      if (!Number.isFinite(expiresAt) || Date.now() > expiresAt) badRequest('confirm_token vencido');
    } catch (err) {
      badRequest('confirm_token invalido', { reason: String(err?.message ?? err) });
    }
    input.confirm_token = confirmToken;
    input.confirm = true;
  }
}

if (input.action === 'history') {
  const page = Number(input.page ?? 1);
  const pageSize = Number(input.page_size ?? 25);
  if (!Number.isInteger(page) || page < 1) badRequest('page invalido. Minimo 1');
  if (!Number.isInteger(pageSize) || pageSize < 1 || pageSize > 100) badRequest('page_size invalido. Debe ser 1..100');
  input.page = page;
  input.page_size = pageSize;
}

return [{ json: input }];

// ── buildInfluencerRegex: regex sólida para matching de ads por influencer ──────
// Genera 5 tipos de patterns:
//   1. Palabras individuales significativas (>= 4 chars), con tolerancia de acentos
//   2. Nombre completo con separadores flexibles: [\s_\-.]{0,3} entre palabras
//   3. Primer + último nombre (salta segundo nombre en nombres de 3 palabras)
//   4. Fuzzy: primer nombre + .{0,8} + primeras 4 letras del apellido
//   5. Concatenación exacta sin acentos (todo junto, minúsculas)
function buildInfluencerRegex(nombreRaw) {
  if (!nombreRaw || !String(nombreRaw).trim()) return '';
  const SEP = '[\\s_\\-.]{0,3}';

  function accentTolerant(word) {
    return word
      .replace(/[aá]/g, '[aá]')
      .replace(/[eé]/g, '[eé]')
      .replace(/[ií]/g, '[ií]')
      .replace(/[oó]/g, '[oó]')
      .replace(/[uú]/g, '[uú]')
      .replace(/[nñ]/g, '[nñ]');
  }

  const clean = String(nombreRaw)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .trim();

  const wordsClean    = clean.split(/\s+/).filter(Boolean);
  const wordsOriginal = String(nombreRaw).toLowerCase().split(/\s+/).filter(Boolean);
  const tolerant      = wordsOriginal.map(w => accentTolerant(w.replace(/[^a-záéíóúñ]/g, '')));

  const patterns = [];

  // 1. Palabras individuales significativas
  tolerant.forEach((tw, i) => { if (wordsClean[i]?.length >= 4) patterns.push(tw); });

  // 2. Nombre completo con SEP
  if (tolerant.length >= 2) patterns.push(tolerant.join(SEP));

  // 3. Primer + último (saltando segundo nombre)
  if (tolerant.length === 3) patterns.push(tolerant[0] + SEP + tolerant[2]);

  // 4. Fuzzy
  if (tolerant.length >= 2) {
    const lastPrefix = tolerant[tolerant.length - 1].slice(0, 4);
    patterns.push(tolerant[0] + '.{0,8}' + lastPrefix);
  }

  // 5. Concatenación sin acentos
  if (wordsClean.length >= 2) patterns.push(wordsClean.join(''));

  return [...new Set(patterns.filter(Boolean))].join('|');
}

// A1: Auto-generar Contrato_ID
const stamp = new Date().toISOString().slice(0,10);
const suffix = Math.random().toString(36).slice(2,6).toUpperCase();
const contratoId = `AK-${stamp}-${suffix}`;

// A2: Auto-derivar Regex_Anuncio del nombre del influencer
// "Farid Dieck" → "farid|dieck|fariddieck"
const nombreRaw = String($json.Cliente ?? '').trim();
const words = nombreRaw.toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .trim()
  .split(/\s+/)
  .filter(Boolean);

let regexAnuncio;
if (words.length === 0) {
  regexAnuncio = 'sin-patron';
} else if (words.length === 1) {
  regexAnuncio = words[0];
} else {
  const parts = [...words, words.join('')];
  regexAnuncio = [...new Set(parts)].join('|');
}

return [{
  json: {
    Contrato_ID:          contratoId,
    Cliente:              String($json.Cliente).trim(),
    Regex_Anuncio: buildInfluencerRegex(String($json.Cliente ?? $json.Nombre ?? '').trim()),
    Fecha_Alta:           String($json.today_tz),
    Fecha_Fin:            String($json.Fecha_Fin),
    Status_Contrato:      'Activo',
    Notificado_Previo:    false,
    Fecha_Notificado_Previo: '',
    Fecha_Finalizacion:   '',
    Updated_At:           $json.request_ts,
  },
}];

const trigger = $items('Validate Input', 0, 0)[0].json;
const showAll = trigger.show_all === true;

if (showAll) {
  // Devolver todos los rows de GS sin filtrar
  const all = items.map(item => ({ json: item.json }));
  all.sort((a, b) => String(a.json.Fecha_Fin ?? '').localeCompare(String(b.json.Fecha_Fin ?? '')));
  return all;
}

// Comportamiento original: filtrar por dias_proximos y Status_Contrato=Activo
const dias = Number(trigger.dias_proximos ?? 7);

function parseYmd(ymd) {
  const [y, m, d] = String(ymd).split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d));
}

const today = parseYmd(trigger.today_tz);
const maxDate = new Date(today.getTime() + dias * 24 * 60 * 60 * 1000);

const out = [];
for (const item of items) {
  const row = item.json;
  const exp = String(row.Fecha_Fin ?? '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(exp)) continue;
  const expDate = parseYmd(exp);
  if (row.Status_Contrato === 'Finalizado') continue;
  if (expDate >= today && expDate <= maxDate) {
    out.push({ json: row });
  }
}

out.sort((a, b) => String(a.json.Fecha_Fin).localeCompare(String(b.json.Fecha_Fin)));
return out;

const req = $items('Validate Input', 0, 0)[0].json;
const idContrato = String(req.Contrato_ID).trim();
const found = items.find((i) => String(i.json.Contrato_ID ?? '').trim() === idContrato);

if (!found) {
  const err = new Error('Contrato no encontrado para extension');
  err.name = 'NotFoundError';
  err.details = { Contrato_ID: idContrato };
  throw err;
}

return [{
  json: {
    ...found.json,
    Contrato_ID: idContrato,
    Fecha_Fin: String(req.Nueva_Fecha_Fin),
    Notificado_Previo: false,
    Updated_At: req.request_ts,
  },
}];

const input = $json ?? {};
const nowIso = new Date().toISOString();
const safeAction = String(input.action ?? 'unknown').trim().toLowerCase();
const correlationId = String(input.correlation_id ?? `ak-f1-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
const logicalExecutionId = String(input.logical_execution_id ?? `${correlationId}:f1:${safeAction}`);

return [{
  json: {
    schema_version: '1.0.0',
    event_type: 'contract.ui.action',
    source_workflow: 'contract-ui-management-v2',
    target_workflow_id: '8mlwAxLtJVrwpLhi',
    timezone: String(input.timezone ?? 'America/Argentina/Buenos_Aires'),
    correlation_id: correlationId,
    logical_execution_id: logicalExecutionId,
    execution: {
      n8n_execution_id: String($execution?.id ?? ''),
      run_type: 'internal_execute_workflow',
      status: 'queued'
    },
    payload: {
      action: safeAction,
      run_mode: String(input.run_mode ?? 'manual'),
      actor: String(input.actor ?? 'ops@adskiller'),
      tracking_id: String(input.tracking_id ?? ''),
      Contrato_ID: String(input.Contrato_ID ?? ''),
      Ad_ID: String(input.Ad_ID ?? ''),
      Fecha_Fin: String(input.Fecha_Fin ?? ''),
      Nueva_Fecha_Fin: String(input.Nueva_Fecha_Fin ?? ''),
      Regex_Anuncio: String(input.Regex_Anuncio ?? ''),
      request_ts: String(input.requested_at ?? input.request_ts ?? nowIso),
      requested_at: String(input.requested_at ?? input.request_ts ?? nowIso),
      today_tz: String(input.today_tz ?? ''),
      timezone: String(input.timezone ?? 'America/Argentina/Buenos_Aires'),
      dry_run: Boolean(input.dry_run ?? false),
      confirm: Boolean(input.confirm ?? false),
      confirm_token: String(input.confirm_token ?? ''),
      max_batch_size: Number(input.max_batch_size ?? input.batch_limit ?? 20),
      batch_limit: Number(input.batch_limit ?? input.max_batch_size ?? 20)
    },
    dispatched_at: nowIso
  }
}];

const source = $json ?? {};
return [{
  json: {
    event: 'internal_chain_dispatch_ok',
    source_workflow: 'contract-ui-management',
    target_workflow_id: '8mlwAxLtJVrwpLhi',
    correlation_id: String(source.correlation_id ?? ''),
    logical_execution_id: String(source.logical_execution_id ?? ''),
    status: 'dispatched',
    timestamp: new Date().toISOString()
  }
}];

const source = $json ?? {};
return [{
  json: {
    event: 'internal_chain_dispatch_error',
    source_workflow: 'contract-ui-management',
    target_workflow_id: '8mlwAxLtJVrwpLhi',
    correlation_id: String(source.correlation_id ?? ''),
    logical_execution_id: String(source.logical_execution_id ?? ''),
    status: 'error',
    error: String(source.error?.message ?? source.message ?? 'unknown_execute_workflow_error'),
    timestamp: new Date().toISOString()
  }
}];

const req = $items('Validate Input', 0, 0)[0].json;
const idContrato = String(req.Contrato_ID).trim();
const actor = String(req.actor ?? 'ops@adskiller');
const reason = String(req.reason ?? 'Cierre manual por operacion').trim();
const found = items.find((i) => String(i.json.Contrato_ID ?? '').trim() === idContrato);
if (!found) { const err = new Error('Contrato no encontrado para baja_manual'); err.name = 'NotFoundError'; err.details = { Contrato_ID: idContrato }; throw err; }
return [{ json: { ...found.json, Contrato_ID: idContrato, Status_Contrato: 'Finalizado', Fecha_Finalizacion: req.request_ts, Updated_At: req.request_ts, Finalizado_By: actor, Finalizado_Reason: reason } }];

// Recibe respuesta del webhook ak-meta-list-v1
const req = $('Normalize Request').first()?.json ?? {};
const idContrato = String(
  req.Contrato_ID ||
  req.contract_id ||
  req.body?.Contrato_ID ||
  req.body?.contract_id ||
  ''
).trim();
// El mock devuelve { statusCode, body: { data: [...] } }
// Con fullResponse:false el body entero es json → datos en json.body.data
const rawJson = $input.first()?.json ?? {};
const data = rawJson.body?.data ?? rawJson.data ?? [];

return [{
  json: {
    ok: true,
    action: 'listar_ads',
    data: {
      contract_id: idContrato,
      total: data.length,
      ads: data.map(ad => ({
        ad_id:     String(ad.id   ?? ''),
        ad_name:   String(ad.name ?? ''),
        ad_status: String(ad.effective_status ?? ad.status ?? 'UNKNOWN').toUpperCase(),
      })),
    },
    meta: {
      correlation_id: req.correlation_id ?? '',
      timestamp: new Date().toISOString(),
    },
  }
}];

const req = $items('Validate Input', 0, 0)[0].json;
const nowIso = new Date().toISOString();
const trackingId = String(req.tracking_id ?? `trk-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`);
const normalizedAction = String(req.action || '').trim();
const dispatchAction = normalizedAction === 'pause_active_preview' ? 'pause_active' : normalizedAction;
const maxBatchSize = Number(req.max_batch_size ?? req.batch_limit ?? 0);
return [{
  json: {
    tracking_id: trackingId,
    correlation_id: String(req.correlation_id),
    logical_execution_id: `${trackingId}:f1:${dispatchAction}`,
    action: dispatchAction,
    run_mode: 'manual',
    actor: String(req.actor ?? 'ops@adskiller'),
    requested_at: req.request_ts ?? nowIso,
    execution_id: String($execution?.id ?? ''),
    status: 'accepted',
    Contrato_ID: String(req.Contrato_ID ?? ''),
    Ad_ID: String(req.Ad_ID ?? ''),
    dry_run: Boolean(req.dry_run ?? false),
    confirm: Boolean(req.confirm ?? false),
    confirm_token: String(req.confirm_token ?? ''),
    max_batch_size: Number.isInteger(maxBatchSize) ? maxBatchSize : 0,
    batch_limit: Number.isInteger(maxBatchSize) ? maxBatchSize : Number(req.batch_limit ?? 0),
    reason: String(req.reason ?? ''),
    timezone: String(req.timezone ?? 'America/Argentina/Buenos_Aires')
  }
}];

const req = $items('Validate Input', 0, 0)[0].json;
const page = Number(req.page ?? 1);
const pageSize = Number(req.page_size ?? 25);
const from = String(req.from ?? '').trim();
const to = String(req.to ?? '').trim();
const resultFilter = String(req.result ?? '').trim().toLowerCase();
const runModeFilter = String(req.run_mode ?? '').trim().toLowerCase();
const executionFilter = String(req.execution_id ?? '').trim();
const correlationFilter = String(req.correlation_id_filter ?? req.correlation_id_query ?? '').trim();
const parseTs = (v) => { const d = new Date(v); return Number.isNaN(d.getTime()) ? null : d; };
const fromDate = from ? parseTs(from) : null;
const toDate = to ? parseTs(to) : null;
let rows = items.map((i) => i.json || {});
rows = rows.filter((row) => {
  const ts = parseTs(row.requested_at ?? row.timestamp ?? row.executed_at ?? '');
  if (fromDate && (!ts || ts < fromDate)) return false;
  if (toDate && (!ts || ts > toDate)) return false;
  if (resultFilter && String(row.status ?? row.result ?? '').toLowerCase() !== resultFilter) return false;
  if (runModeFilter && String(row.run_mode ?? '').toLowerCase() !== runModeFilter) return false;
  if (executionFilter && String(row.execution_id ?? '') !== executionFilter) return false;
  if (correlationFilter && String(row.correlation_id ?? '') !== correlationFilter) return false;
  return true;
});
rows.sort((a, b) => String(b.requested_at ?? b.timestamp ?? '').localeCompare(String(a.requested_at ?? a.timestamp ?? '')));
const total = rows.length;
const start = (page - 1) * pageSize;
const paged = rows.slice(start, start + pageSize).map((row) => ({ execution_id: String(row.execution_id ?? ''), tracking_id: String(row.tracking_id ?? ''), correlation_id: String(row.correlation_id ?? ''), action: String(row.action ?? ''), run_mode: String(row.run_mode ?? ''), result: String(row.status ?? row.result ?? ''), actor: String(row.actor ?? ''), executed_at: String(row.requested_at ?? row.timestamp ?? row.executed_at ?? '') }));
return [{ json: { total, page, page_size: pageSize, items: paged } }];

const req = $items('Validate Input', 0, 0)[0].json;
const contractId = String(req.Contrato_ID ?? '').trim();
const maxBatchSize = Number(req.max_batch_size ?? req.batch_limit ?? 20);
const actor = String(req.actor ?? 'ops@adskiller').trim();
const ttlMs = 10 * 60 * 1000;

function encodeBase64Url(value) {
  return Buffer.from(value, 'utf8')
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

const candidates = items
  .filter((i) => String(i.json.Contrato_ID ?? '').trim() === contractId)
  .filter((i) => String(i.json.Status_Contrato ?? '').trim().toLowerCase() === 'activo')
  .slice(0, maxBatchSize)
  .map((i) => ({
    ad_id: String(i.json.Ad_ID ?? ''),
    ad_name: String(i.json.Ad_Name ?? ''),
    contract_id: contractId
  }));

const nowMs = Date.now();
const expiresAt = nowMs + ttlMs;
const tokenPayload = {
  contract_id: contractId,
  actor,
  max_batch_size: maxBatchSize,
  issued_at_epoch_ms: nowMs,
  expires_at_epoch_ms: expiresAt,
  candidate_count: candidates.filter((x) => x.ad_id).length
};
const confirmToken = encodeBase64Url(JSON.stringify(tokenPayload));

return [{
  json: {
    dry_run: true,
    contract_id: contractId,
    max_batch_size: maxBatchSize,
    total_candidates: candidates.length,
    would_pause: candidates.filter((x) => x.ad_id).length,
    confirm_token: confirmToken,
    confirm_token_expires_at: new Date(expiresAt).toISOString(),
    items: candidates
  }
}];

const query = String($('Validate Input').first().json.q ?? '').toLowerCase().trim();
const allItems = $input.all();
const matches = allItems.filter(item => {
  const cliente = String(item.json.Cliente ?? '').toLowerCase();
  return !query || cliente.includes(query);
});
return [{ json: {
  ok: true,
  action: 'search',
  query: query,
  total: matches.length,
  data: matches.map(i => i.json),
  correlation_id: $('Validate Input').first().json.correlation_id,
  execution_id: $execution.id
} }];

const req = $('Normalize Request').first()?.json ?? {};
const idContrato = String(
  req.Contrato_ID || req.contract_id ||
  req.body?.Contrato_ID || req.body?.contract_id || ''
).trim();

const allRows = $input.all();
const contract = allRows.find(item =>
  String(item.json.Contrato_ID ?? '').trim() === idContrato
);
if (!contract) {
  return [{ json: { ok: false, error: 'contrato_no_encontrado', contract_id: idContrato } }];
}

// Generar regex on-the-fly desde Cliente — nunca leer Regex_Anuncio del Sheet
// Sin backslashes: .{0,3} como separador flexible, normalize() quita tildes
function buildRegex(nombreRaw) {
  if (!nombreRaw || !String(nombreRaw).trim()) return '';
  const clean = String(nombreRaw)
    .normalize('NFD')
