  } else {
    patterns.push(words.join('.{0,3}'));
    if (words.length === 3) patterns.push(words[0] + '.{0,3}' + words[2]);
    patterns.push(words[0] + '.{0,8}' + words[words.length-1].slice(0, 4));
    patterns.push(words.join(''));
  }
  return [...new Set(patterns)].join('|');
}

